  KEY `ix_students_is_active` (`is_active`),
  KEY `idx_students_status` (`school_id`,`status`),
  CONSTRAINT `fk_students_school_id_schools` FOREIGN KEY (`school_id`) REFERENCES `schools` (`id`)
